381		/**
382		 * Gets infrastructure logger.
383		 * @param {string | (() => string)} name name of the logger, or function called once to get the logger name
384		 * @returns {Logger} a logger with that name
385		 */
386		getInfrastructureLogger(name) {
387			if (!name) {
388				throw new TypeError(
389					"Compiler.getInfrastructureLogger(name) called without a name"
390				);
391			}
392			return new Logger(
393				(type, args) => {
394					if (typeof name === "function") {
395						name = name();
396						if (!name) {
397							throw new TypeError(
398								"Compiler.getInfrastructureLogger(name) called with a function not returning a name"
399							);
400						}
401					}
402					if (
403						this.hooks.infrastructureLog.call(name, type, args) === undefined &&
404						this.infrastructureLogger !== undefined
405					) {
406						this.infrastructureLogger(name, type, args);
407					}
408				},
409				(childName) => {
410					if (typeof name === "function") {
411						if (typeof childName === "function") {
412							return this.getInfrastructureLogger(() => {
413								if (typeof name === "function") {
414									name = name();
415									if (!name) {
416										throw new TypeError(
417											"Compiler.getInfrastructureLogger(name) called with a function not returning a name"
418										);
419									}
420								}
421								if (typeof childName === "function") {
422									childName = childName();
423									if (!childName) {
424										throw new TypeError(
425											"Logger.getChildLogger(name) called with a function not returning a name"
426										);
427									}
428								}
429								return `${name}/${childName}`;
430							});
431						}
432						return this.getInfrastructureLogger(() => {
433							if (typeof name === "function") {
434								name = name();
435								if (!name) {
436									throw new TypeError(
437										"Compiler.getInfrastructureLogger(name) called with a function not returning a name"
438									);
439								}
440							}
441							return `${name}/${childName}`;
442						});
443					}
444					if (typeof childName === "function") {
445						return this.getInfrastructureLogger(() => {
446							if (typeof childName === "function") {
447								childName = childName();
448								if (!childName) {
449									throw new TypeError(
450										"Logger.getChildLogger(name) called with a function not returning a name"
451									);
452								}
453							}
454							return `${name}/${childName}`;
455						});
456					}
457					return this.getInfrastructureLogger(`${name}/${childName}`);
458				}
