497		/**
498		 * Release fields on a finished compilation that nothing reads after emit,
499		 * so the heap can shrink while user code still holds the Stats reference.
500		 * Recurses into child compilations. Stats output is preserved — only
501		 * codeGen byproducts are dropped.
502		 * @param {Compilation} compilation finished compilation to slim down
503		 * @returns {void}
504		 */
505		_releaseUnusedCompilationData(compilation) {
506			for (const child of compilation.children) {
507				this._releaseUnusedCompilationData(child);
508			}
509			// Rendered source per (module × runtime) — used only during seal/emit,
510			// never read by Stats, and not serialized to the persistent cache.
511			if (compilation.codeGenerationResults !== undefined) {
512				compilation.codeGenerationResults.map.clear();
513			}
514		}
