280								refModule.buildMeta !== undefined &&
281								refModule.buildMeta.sideEffectFree
282							)
283						) {
284							state = true;
285						} else if (refModule._isEvaluatingSideEffects) {
286							ctx.circular = true;
287							state = ModuleGraphConnection.CIRCULAR_CONNECTION;
288						} else {
289							// Descend
290							indexStack[top] = index;
291							currentStack[top] = current;
292							refModule._isEvaluatingSideEffects = true;
293							modStack.push(refModule);
294							depsStack.push(refModule.dependencies);
295							indexStack.push(0);
296							currentStack.push(false);
297							descended = true;
298							break;
299						}
300					} else {
301						ctx.circular = true;
302						state = refModule.getSideEffectsConnectionState(moduleGraph);
303					}
304				} else {
305					state = dep.getModuleEvaluationSideEffectsState(moduleGraph);
306				}
307	
308				if (state === true) {
309					recordSideEffectsBailout(topMod, moduleGraph, dep);
310					topMod._isEvaluatingSideEffects = false;
311					topMod._sideEffectsStateGraph = moduleGraph;
312					topMod._sideEffectsStateValue = true;
313					modStack.pop();
314					depsStack.pop();
315					indexStack.pop();
316					currentStack.pop();
317					pending = true;
318					descended = true;
319					break;
320				}
321				if (state !== ModuleGraphConnection.CIRCULAR_CONNECTION) {
322					current = ModuleGraphConnection.addConnectionStates(current, state);
323				}
324				index++;
325			}
326	
327			if (descended) continue;
328	
329			topMod._isEvaluatingSideEffects = false;
330			if (!ctx.circular) {
331				topMod._sideEffectsStateGraph = moduleGraph;
332				topMod._sideEffectsStateValue = current;
333			}
334			pending = current;
335			modStack.pop();
336			depsStack.pop();
337			indexStack.pop();
338			currentStack.pop();
