349	/**
350	 * Walks back up a stack of linear-chain ancestors, applying the result
351	 * `state` of the chain's tail to each ancestor. Each ancestor in the
352	 * stack had exactly one `HarmonyImportSideEffectDependency` returning
353	 * `state`, so its result is just `state` (with the usual aggregation
354	 * rules) and we can avoid building per-frame `current` accumulators.
355	 * @param {(NormalModule | Dependency)[] | null} ancestors interleaved stack of `[mod, sideEffectDep, mod, sideEffectDep, …]` in descent order; `null` if there were none
356	 * @param {ConnectionState} state result from the chain's tail
357	 * @param {ModuleGraph} moduleGraph the module graph
358	 * @param {SideEffectsWalkContext} ctx per-walk cycle-tracking context
359	 * @returns {ConnectionState} the root ancestor's result
360	 */
361	const propagateLinearResult = (ancestors, state, moduleGraph, ctx) => {
362		if (ancestors === null) return state;
363		while (ancestors.length > 0) {
364			const dep = /** @type {Dependency} */ (ancestors.pop());
365			const ancestor = /** @type {NormalModule} */ (ancestors.pop());
366			ancestor._isEvaluatingSideEffects = false;
367	
368			if (state === true) {
369				recordSideEffectsBailout(ancestor, moduleGraph, dep);
370				// `true` is monotonic — safe to cache regardless of cycle status.
371				ancestor._sideEffectsStateGraph = moduleGraph;
372				ancestor._sideEffectsStateValue = true;
373			} else if (state === ModuleGraphConnection.CIRCULAR_CONNECTION) {
374				// CIRCULAR_CONNECTION is filtered before folding into `current`,
375				// so the ancestor's `current` stays at its initial `false`. From
376				// this point upward the propagated state is `false`, and the
377				// cycle taint prevents memoization further up (handled by
378				// `ctx.circular`).
379				state = false;
380			} else if (!ctx.circular) {
381				ancestor._sideEffectsStateGraph = moduleGraph;
382				ancestor._sideEffectsStateValue = state;
383			}
384		}
385		return state;
386	};
