388	/**
389	 * Recursive form of the side-effects walker. Folds the descent through
390	 * `HarmonyImportSideEffectDependency.getModuleEvaluationSideEffectsState`
391	 * directly into the loop so each module costs only one V8 stack frame
392	 * (vs. two in the original recursive code).
393	 *
394	 * Linear-chain heads (modules with exactly one
395	 * `HarmonyImportSideEffectDependency` to another `NormalModule`) are
396	 * walked iteratively inside the function via an explicit
397	 * `linearAncestors` stack — no additional V8 frame per descent — and
398	 * their results are propagated back up by `propagateLinearResult`. This
399	 * keeps stack consumption at O(1) for the common deep-import-chain
400	 * pattern that motivated #20986 and also avoids the heavier iterative
401	 * fallback.
402	 *
403	 * Falls back to `walkSideEffectsIterative` only when a *non-linear*
404	 * walk reaches `SIDE_EFFECTS_RECURSION_LIMIT` — i.e. a deep tree, where
405	 * each level genuinely needs its own recursion frame.
406	 *
407	 * Caches the result on the module when the walk did not encounter a
408	 * cycle, so subsequent queries (e.g. repeated lookups during
409	 * `SideEffectsFlagPlugin`'s incoming-connection optimization and its
410	 * `exportInfo.getTarget` callbacks) return in O(1).
411	 * @param {NormalModule} mod the module being walked
412	 * @param {ModuleGraph} moduleGraph the module graph
413	 * @param {number} depth current recursion depth (only counts true V8 frames)
414	 * @param {EXPECTED_ANY} SideEffectDep `HarmonyImportSideEffectDependency` constructor, resolved once at the public entry to avoid repeated `require` lookups in the recursive call
415	 * @param {SideEffectsWalkContext} ctx per-walk cycle-tracking context
416	 * @returns {ConnectionState} the side-effects connection state
417	 */
418	const walkSideEffectsRecursive = (
419		mod,
420		moduleGraph,
421		depth,
422		SideEffectDep,
423		ctx
424	) => {
425		// Interleaved `[mod, linearDep, mod, linearDep, …]` for the linear
426		// chain head; `null` until the first descent.
427		/** @type {(NormalModule | Dependency)[] | null} */
428		let linearAncestors = null;
429	
430		// Walk the linear-chain head iteratively. Every loop iteration peels
431		// off one module without consuming a V8 stack frame.
432		while (true) {
433			if (mod._sideEffectsStateGraph === moduleGraph) {
434				return propagateLinearResult(
435					linearAncestors,
436					/** @type {ConnectionState} */ (mod._sideEffectsStateValue),
437					moduleGraph,
438					ctx
439				);
440			}
441	
442			if (mod.factoryMeta !== undefined) {
443				if (mod.factoryMeta.sideEffectFree) {
444					return propagateLinearResult(linearAncestors, false, moduleGraph, ctx);
445				}
446				if (mod.factoryMeta.sideEffectFree === false) {
447					return propagateLinearResult(linearAncestors, true, moduleGraph, ctx);
448				}
449			}
450			if (!(mod.buildMeta !== undefined && mod.buildMeta.sideEffectFree)) {
451				return propagateLinearResult(linearAncestors, true, moduleGraph, ctx);
452			}
453			if (mod._isEvaluatingSideEffects) {
454				ctx.circular = true;
455				return propagateLinearResult(
456					linearAncestors,
457					ModuleGraphConnection.CIRCULAR_CONNECTION,
458					moduleGraph,
459					ctx
460				);
461			}
462	
463			// A real ESM module's `dependencies` typically include one
464			// `HarmonyImportSideEffectDependency` plus several non-recursive deps
465			// (export specifiers, const dependencies, …) that report
466			// `false`/`CIRCULAR_CONNECTION` from
467			// `getModuleEvaluationSideEffectsState`. Walk the deps in order
468			// here: as long as at most one is a `SideEffectDep` and no
469			// non-recursive dep triggers a bailout or contributes a non-`false`
470			// state, we can still tail-call iteratively through that one
471			// `SideEffectDep` — no V8 frame needed. This is what keeps the
472			// 1300-module cyclic chain from #20986 from overflowing V8's stack
473			// even though each generated module has multiple `dependencies`.
474			const deps = mod.dependencies;
475			/** @type {Dependency | null} */
476			let linearDep = null;
477			/** @type {ConnectionState} */
478			let nonRecursiveCurrent = false;
479			let linearOk = true;
480			for (let i = 0; i < deps.length; i++) {
481				const dep = deps[i];
482				if (dep instanceof SideEffectDep) {
483					if (linearDep !== null) {
484						// Two `SideEffectDep`s in the same module — fall back to
485						// the general walk so each can recurse normally.
486						linearOk = false;
487						break;
488					}
489					linearDep = dep;
490				} else {
491					const state = dep.getModuleEvaluationSideEffectsState(moduleGraph);
492					if (state === true) {
493						recordSideEffectsBailout(mod, moduleGraph, dep);
494						mod._sideEffectsStateGraph = moduleGraph;
495						mod._sideEffectsStateValue = true;
496						return propagateLinearResult(linearAncestors, true, moduleGraph, ctx);
497					}
498					if (state !== ModuleGraphConnection.CIRCULAR_CONNECTION) {
499						nonRecursiveCurrent = ModuleGraphConnection.addConnectionStates(
500							nonRecursiveCurrent,
501							state
502						);
503					}
504				}
505			}
506	
507			if (!linearOk || nonRecursiveCurrent !== false) {
508				// Multiple `SideEffectDep`s, or a non-recursive dep contributed
509				// a non-`false` state (e.g. `TRANSITIVE_ONLY`). The linear
510				// propagation rule "ancestor's current = chain state" no longer
511				// holds, so fall back to the general walk.
512				break;
513			}
514	
515			if (linearDep === null) {
516				// No `SideEffectDep` — the module is a leaf as far as the
517				// side-effects graph is concerned. Cache and propagate `false`.
518				if (!ctx.circular) {
519					mod._sideEffectsStateGraph = moduleGraph;
520					mod._sideEffectsStateValue = false;
521				}
522				return propagateLinearResult(linearAncestors, false, moduleGraph, ctx);
523			}
524	
525			const refModule = moduleGraph.getModule(linearDep);
526			if (!refModule) {
527				recordSideEffectsBailout(mod, moduleGraph, linearDep);
528				mod._sideEffectsStateGraph = moduleGraph;
529				mod._sideEffectsStateValue = true;
530				return propagateLinearResult(linearAncestors, true, moduleGraph, ctx);
531			}
532			if (!(refModule instanceof NormalModule)) {
533				// Non-NormalModule's `getSideEffectsConnectionState` re-enters
534				// the public method; defer to the general walk for safety.
535				break;
536			}
537	
538			mod._isEvaluatingSideEffects = true;
539			if (linearAncestors === null) linearAncestors = [];
540			// Push (mod, linearDep) so `propagateLinearResult` records bailouts
541			// against the actual `SideEffectDep` that triggered the descent —
542			// which may not be `dependencies[0]` when the module also has
543			// export / const dependencies.
544			linearAncestors.push(mod, linearDep);
545			mod = refModule;
546			continue;
547		}
548	
549		// Non-linear walk. Each genuine recursive call costs one V8 frame, so
550		// honour the depth limit here.
551		if (depth >= SIDE_EFFECTS_RECURSION_LIMIT) {
552			return propagateLinearResult(
553				linearAncestors,
554				walkSideEffectsIterative(mod, moduleGraph, ctx),
555				moduleGraph,
556				ctx
557			);
558		}
559	
560		mod._isEvaluatingSideEffects = true;
561		/** @type {ConnectionState} */
562		let current = false;
563	
564		for (const dep of mod.dependencies) {
565			/** @type {ConnectionState} */
566			let state;
567			if (dep instanceof SideEffectDep) {
568				const refModule = moduleGraph.getModule(dep);
569				if (!refModule) {
570					state = true;
571				} else if (refModule instanceof NormalModule) {
572					state = walkSideEffectsRecursive(
573						refModule,
574						moduleGraph,
575						depth + 1,
576						SideEffectDep,
577						ctx
578					);
579				} else {
580					// Non-NormalModule's `getSideEffectsConnectionState` (notably
581					// `ConcatenatedModule` delegating to its root) re-enters the
582					// public method and may walk through modules that the outer
583					// walk has marked as evaluating. We can't observe whether
584					// the inner walk hit a cycle that reflected the outer's
585					// state, so treat the walk as cycle-tainted and skip the
586					// cache for safety.
587					ctx.circular = true;
588					state = refModule.getSideEffectsConnectionState(moduleGraph);
589				}
590			} else {
591				state = dep.getModuleEvaluationSideEffectsState(moduleGraph);
592			}
593	
594			if (state === true) {
595				recordSideEffectsBailout(mod, moduleGraph, dep);
596				mod._isEvaluatingSideEffects = false;
597				// `true` is monotonic — once any dep declares side effects, the
598				// answer is `true` regardless of how cycles resolve, so it's
599				// always safe to memoize.
600				mod._sideEffectsStateGraph = moduleGraph;
601				mod._sideEffectsStateValue = true;
602				return propagateLinearResult(linearAncestors, true, moduleGraph, ctx);
603			}
604			if (state !== ModuleGraphConnection.CIRCULAR_CONNECTION) {
605				current = ModuleGraphConnection.addConnectionStates(current, state);
606			}
607		}
608	
609		mod._isEvaluatingSideEffects = false;
610	
611		// Only memoize when no cycle has been observed anywhere in the walk
612		// since the public entry. A cycle anywhere can affect any ancestor's
613		// result (the back-edge target's contribution is hidden by
614		// CIRCULAR_CONNECTION short-circuiting), so this single flag is the
615		// conservative-but-cheap approximation of "this subtree's result is
616		// independent of cycle context". The public entry resets the flag.
617		if (!ctx.circular) {
618			mod._sideEffectsStateGraph = moduleGraph;
619			mod._sideEffectsStateValue = current;
620		}
621		return propagateLinearResult(linearAncestors, current, moduleGraph, ctx);
622	};
